import json, sys, collections
lines = open(sys.argv[1], encoding='utf-8').readlines()
c = collections.Counter()
samples = {}
ends = {}
for line in lines:
    d = json.loads(line)
    t = d.get('type')
    data = d.get('data') or {}
    if t == 'hook.start':
        ht = data.get('hookType','?')
        c[ht] += 1
        if ht not in samples: samples[ht] = data.get('input', {})
    elif t == 'hook.end':
        ht = data.get('hookType','?')
        if ht not in ends: ends[ht] = data
for k in sorted(c): print(c[k], 'x', k)
print('---input keys---')
for k, v in samples.items():
    print(k, '->', list(v.keys()) if isinstance(v, dict) else type(v))
print('---end sample---')
for k, v in list(ends.items())[:3]:
    print(k, '->', json.dumps(v, default=str)[:300])
