#requires -Version 7.4
# Envelope.psm1 -- extract a dispatch's outcome envelope from its report (Task B.1).
#
# WHY THE TRANSCRIPT, NOT A PAYLOAD FIELD (C2R1-M3): the SubagentStop payload carries
# agent_transcript_path (spec S2.3, design A1). The producer reads the last assistant
# message FROM that transcript and parses the fenced starcar-artifact envelope out of it.
# An earlier revision extracted from a `last_assistant_message` payload field the spec
# never blessed and a reviewer could not verify; the transcript is authoritative and the
# payload field is unused.
#
# Two functions, both returning a pscustomobject (the module family's shape, matching
# Artifact.psm1's Test-StarcarArtifact -> { Valid; Errors; Discoveries }; never a
# hashtable):
#   Get-LastAssistantText  -> { Text; Errors }
#   Get-StarcarEnvelope    -> { Found; Outcome; Findings; Abstract; Fault }
#
# -Encoding UTF8 on every read is load-bearing, not decoration: pwsh's Get-Content is
# UTF-8 by default on 7.x, but stating it keeps the intent explicit and survives a floor
# change (the Land-Verdict.ps1 scar: an ANSI default silently mangled a transcript).

Set-StrictMode -Version Latest

function Get-LastAssistantText {
    <#
      Returns the text of the LAST assistant message in a Claude Code JSONL transcript:
      the last line whose message.role == 'assistant', with its content[].text parts
      (type == 'text') joined. On an absent or unparseable transcript, Text is $null and
      Errors carries exactly one entry (never N) -- one fault per read, matching the
      board-level one-fault rule the rest of the harness uses.
    #>
    param([Parameter(Mandatory)] [string]$TranscriptPath)

    $errors = New-Object System.Collections.Generic.List[string]

    if (-not (Test-Path -LiteralPath $TranscriptPath)) {
        $errors.Add("transcript not found: $TranscriptPath")
        return [pscustomobject]@{ Text = $null; Errors = @($errors) }
    }

    $lastText = $null
    try {
        $lines = Get-Content -LiteralPath $TranscriptPath -Encoding UTF8 -ErrorAction Stop
    } catch {
        $errors.Add("transcript unreadable: $TranscriptPath ($($_.Exception.Message))")
        return [pscustomobject]@{ Text = $null; Errors = @($errors) }
    }

    foreach ($line in $lines) {
        if ([string]::IsNullOrWhiteSpace($line)) { continue }
        $obj = $null
        try { $obj = $line | ConvertFrom-Json } catch { continue }

        $msgProp = $obj.PSObject.Properties['message']
        if (-not $msgProp) { continue }
        $msg = $msgProp.Value

        $roleProp = $msg.PSObject.Properties['role']
        if (-not $roleProp -or $roleProp.Value -ne 'assistant') { continue }

        $contentProp = $msg.PSObject.Properties['content']
        if (-not $contentProp) { continue }
        $content = $contentProp.Value

        $text = ''
        if ($content -is [string]) {
            $text = $content
        } else {
            foreach ($item in $content) {
                $typeProp = $item.PSObject.Properties['type']
                $textProp = $item.PSObject.Properties['text']
                if ($typeProp -and $typeProp.Value -eq 'text' -and $textProp) {
                    $text += [string]$textProp.Value
                }
            }
        }
        $lastText = $text
    }

    if ($null -eq $lastText) {
        $errors.Add("no assistant message with text found in $TranscriptPath")
    }

    [pscustomobject]@{ Text = $lastText; Errors = @($errors) }
}

function Get-StarcarEnvelope {
    <#
      Parse the report's outcome envelope: a fenced block, info string starcar-artifact,
      carrying outcome, findings, abstract (spec S2.3). Faults, both landing with the body
      intact (S2.3):
        Fault = 'absent'    -> no fence at all (a brief failure)
        Fault = 'malformed' -> a fence exists but a required field is missing (a producer
                               failure)
        Fault = $null       -> Found, all three fields present
      LAST fence wins when a report carries more than one block (repeat-envelope
      precedent, Land-Verdict.ps1's Get-ResultBlockForTask last-wins return -- the later
      notification is the current one).
      findings/abstract may span multiple lines: a value runs from its `key:` line until
      the next field key or the end of the block, and is preserved verbatim (LF-joined).
    #>
    param([Parameter(Mandatory)] [AllowEmptyString()] [string]$Text)

    $normalised = $Text -replace "`r`n", "`n"

    # Fenced blocks whose info string is exactly starcar-artifact. Leading whitespace on
    # the fence line is tolerated (markdown permits up to three spaces of indent); the
    # capture is the block body between the opening info line and the closing fence.
    $pattern = '(?ms)^[ \t]*```starcar-artifact[ \t]*\n(.*?)\n[ \t]*```[ \t]*$'
    $matchList = [regex]::Matches($normalised, $pattern)

    if ($matchList.Count -eq 0) {
        return [pscustomobject]@{
            Found = $false; Outcome = $null; Findings = $null; Abstract = $null; Fault = 'absent'
        }
    }

    # Last fence wins.
    $body = $matchList[$matchList.Count - 1].Groups[1].Value

    $fields = @{}
    $current = $null
    foreach ($line in ($body -split "`n")) {
        if ($line -match '^(outcome|findings|abstract):[ ]?(.*)$') {
            $current = $Matches[1]
            $fields[$current] = $Matches[2]
        } elseif ($current) {
            $fields[$current] += "`n" + $line
        }
    }

    $outcome  = if ($fields.ContainsKey('outcome'))  { $fields['outcome'].TrimEnd() }  else { $null }
    $findings = if ($fields.ContainsKey('findings')) { $fields['findings'].TrimEnd() } else { $null }
    $abstract = if ($fields.ContainsKey('abstract')) { $fields['abstract'].TrimEnd() } else { $null }

    # A fence with a missing (or empty) required field is malformed, not found: the body
    # is present but does not carry the three payloads the record needs.
    $complete = -not (
        [string]::IsNullOrEmpty($outcome) -or
        [string]::IsNullOrEmpty($findings) -or
        [string]::IsNullOrEmpty($abstract)
    )

    [pscustomobject]@{
        Found    = [bool]$complete
        Outcome  = $outcome
        Findings = $findings
        Abstract = $abstract
        Fault    = if ($complete) { $null } else { 'malformed' }
    }
}

Export-ModuleMember -Function Get-LastAssistantText, Get-StarcarEnvelope

function Get-TranscriptLines {
    param([string]$Path)
    # -Encoding UTF8 is load-bearing, not decoration. PowerShell 5.1's Get-Content
    # defaults to the system ANSI codepage, which silently mangles every non-ASCII
    # character in the transcript (a section sign becomes two characters). That makes
    # the word VERBATIM in this file's own header false, quietly, in a way only the
    # SHA-256 would ever expose. Caught on this script's first real run.
    if ($Path -and (Test-Path $Path)) { return Get-Content $Path -Encoding UTF8 }
    throw "No readable transcript. Pass -TranscriptPath, or land from an Entire checkpoint blob with: git show entire/checkpoints/v1:<path>/transcript.jsonl"
}

function Get-ResultBlockForTask {
    # A completed dispatch arrives as a task-notification carrying <task-id> and a
    # <result> block. Matching on the task id rather than on a phrase keeps this
    # deterministic -- a phrase can appear in the conductor's own commentary, a task
    # id cannot.
    param([string[]]$Lines, [string]$Id)

    $found = @()
    foreach ($line in $Lines) {
        if (-not $line) { continue }
        if ($line -notmatch [regex]::Escape($Id)) { continue }
        if ($line -notmatch '<result>') { continue }

        $obj = $null
        try { $obj = $line | ConvertFrom-Json } catch { continue }
        if (-not $obj.PSObject.Properties.Name.Contains('content')) { continue }

        $text = ''
        if ($obj.content -is [string]) {
            $text = $obj.content
        } else {
            foreach ($item in $obj.content) {
                if ($item.PSObject.Properties.Name -contains 'text') { $text = $text + $item.text }
            }
        }
        if (-not $text) { continue }
        if ($text -notmatch [regex]::Escape("<task-id>$Id</task-id>")) { continue }

        $s = $text.IndexOf('<result>')
        $e = $text.IndexOf('</result>')
        if ($s -lt 0 -or $e -lt $s) { continue }
        $found += $text.Substring($s + 8, $e - $s - 8)
    }

    if ($found.Count -eq 0) { throw "No <result> block found for task id '$Id'. A dispatch that never completed has no verdict to land." }
    # A task-id can notify more than once (an agent resumed by SendMessage). The LAST
    # result is the current one; landing an earlier one would publish a superseded verdict.
    return $found[$found.Count - 1]
}

function ConvertTo-PortablePaths {
    # Rewrite operator-environment paths to portable placeholders BEFORE hashing.
    #
    # This is normalisation, not curation. The record is what happened - findings,
    # verdicts, wrong calls, rejected work. An operator's home directory is not a
    # finding; it is an accident of where a file happened to sit, and it is the one
    # thing in these artifacts a stranger cannot use. Law 7 wants "<repo>/docs/..."
    # because that is reproducible on their machine; the absolute path is noise that
    # also happens to publish a username to a public repo.
    #
    # Portability and honesty point the same way here, so nothing is traded. What
    # would be curation - softening a finding, dropping a Major, flattering a verdict -
    # is exactly what the north star forbids and is untouched by this.
    #
    # Three properties keep it honest:
    #   1. It runs BEFORE hashing, so it is part of writing the record, not editing a
    #      record already written. Applied afterwards it would be tampering, and the
    #      integrity line would (correctly) refuse it.
    #   2. The rules are mechanical, narrow, and declared in the landed file, so a
    #      reader knows exactly what was substituted and can reason about it.
    #   3. Entire's checkpoint branch keeps the UN-normalised original. Nothing is
    #      destroyed; the raw text is one git grep away.
    #
    # Deliberately narrow: only known environment roots, longest-first. Aggressive
    # substitution would mangle a finding that is legitimately ABOUT a path.
    param([string]$Text)

    $repoRoot = (git rev-parse --show-toplevel 2>$null)
    if ($LASTEXITCODE -ne 0) { $repoRoot = '' }
    if ($repoRoot) { $repoRoot = $repoRoot.Replace('/', '\') }

    $rules = @()
    if ($repoRoot) { $rules += @{ From = $repoRoot; To = '<repo>' } }
    if ($env:USERPROFILE) { $rules += @{ From = $env:USERPROFILE; To = '~' } }

    # Longest first, so the repo root inside a home directory wins over the home rule.
    $rules = $rules | Sort-Object { $_.From.Length } -Descending

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://starcar.dev/schema/starcar-artifact/1",
  "title": "StarCar dispatch-lifecycle artifact",
  "description": "Spec S3 preamble: the schema owns six contracts - field names, types, ordering, identity, the index format, and the path-normalisation substitution rule. This file governs fields and types (plus the conditional-requirement shape); ordering, the index format, and the normalisation rule are declared in schema/index-format.md, which this file does not duplicate (Law 6).",
  "type": "object",
  "properties": {
    "schema": {
      "const": "starcar-artifact/1"
    },
    "kind": {
      "type": "string",
      "description": "Recognition vocabulary lives in schema/vocab/kinds.json as DATA, never as a schema enum here (spec S3.2: an unrecognised kind must be a discovery, not a validation failure)."
    },
    "subject": {
      "type": "string",
      "description": "THE identity key (ruling R2). For the three dispatch kinds (dispatched, returned, presumed-lost) its value IS the dispatch id. There is no separate dispatch_id field."
    },
    "session_id": {
      "type": "string"
    },
    "at": {
      "type": "string",
      "format": "date-time",
      "description": "ISO-8601 UTC. Latest-at wins on supersession (spec S3.1)."
    },
    "outcome": {
      "type": "string",
      "description": "Recognition vocabulary lives in schema/vocab/outcomes.json as DATA, never as a schema enum here, for the same reason as kind."
    },
    "findings": {
      "type": "string"
    },
    "abstract": {
      "type": "string",
      "description": "The third envelope payload field (spec S2.3), alongside outcome and findings - the human-readable summary a board renders."
    },
    "envelope": {
      "type": "string",
      "enum": ["absent", "malformed"],
      "description": "Records the envelope fault class. Only meaningful on kind=returned. Absent and malformed are different faults (spec S2.3); both land with the body intact. This is a closed, schema-owned fault-class enum, not a recognition vocabulary, so it is exempt from the vocabularies-as-data rule."
    },
    "budget": {
      "type": "number",
      "description": "Seconds. Optional - the shop default applies at FOLD time, never infinite. The default is the detector's to apply, never the schema's."
    },
    "basis": {
      "type": "object",
      "description": "Required when kind=presumed-lost (spec S3.3).",
      "properties": {
        "observed": {},
        "by": {},
        "against_budget": {}
      },
      "required": ["observed", "by", "against_budget"]
    },
    "cost": {
      "type": "object",
      "description": "Optional - producer-optional by Law 7 (spec S3.4)."
    },
    "context_peak_tokens": {
      "type": "number"
    },
    "producer": {
      "type": "string",
      "description": "Optional. Not spec-mandated (S3.4 governs cost/context optionality and names no such field). Basis: Law 7 metadata naming the emitting adapter, optional exactly as cost is."
    },
    "model": {
      "type": "string",
      "description": "Optional, dispatched-only. Issue #26: an observed producer field with clear provenance, not spec-mandated - written by scripts/Produce-Artifact.ps1:285 only when kind=dispatched, sourced from the Task tool_response's resolvedModel (scripts/Produce-Artifact.ps1:204). Same open-posture-extra class as producer/cost. Not part of the canonical field order in schema/index-format.md (a disclosed producer deviation, not an omission)."
    },
    "body_file": {
      "type": "string",
      "description": "Optional, returned-only. Issue #26: an observed producer field with clear provenance, not spec-mandated - written by scripts/Migrate-Verdicts.ps1:152 on migrated verdict records, the store-root-relative path to the verdict's landed markdown body. That script's own header (scripts/Migrate-Verdicts.ps1:22) already calls it 'an open-posture extra'. Same open-posture-extra class as producer/cost. Not part of the canonical field order in schema/index-format.md (a disclosed producer deviation, not an omission)."
    },
    "normalisation": {
      "type": "array",
      "description": "Declared in each landed artifact. Empty array means nothing was substituted.",
      "items": {
        "type": "object",
        "properties": {
          "from_class": { "type": "string" },
          "to": { "type": "string" }
        },
        "required": ["from_class", "to"]
      }
    },
    "integrity": {
      "type": "string",
      "pattern": "^sha256:[0-9a-f]{64}$",
      "description": "sha256:<hex> over the canonical body."
    }
  },
  "required": ["schema", "kind", "subject", "session_id", "at", "normalisation", "integrity"],
  "allOf": [
    {
      "if": {
        "properties": { "kind": { "const": "returned" } },
        "required": ["kind"]
